(function () {
  function addStyle() { if (document.getElementById('dps-style')) return; var s = document.createElement('style'); s.id = 'dps-style'; s.textContent = '.dps-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.dps-dice{display:flex;gap:12px;align-items:center;justify-content:center;margin:12px 0}.dps-die{width:64px;height:64px;border:2px solid #cbd5e1;border-radius:14px;background:#f8fafc;display:flex;align-items:center;justify-content:center;font-size:34px;cursor:pointer;transition:.2s}.dps-die:hover{border-color:#007bff;transform:translateY(-2px)}.dps-actions{display:flex;gap:8px;flex-wrap:wrap;justify-content:center}.dps-bars{display:grid;grid-template-columns:repeat(11,1fr);gap:6px;align-items:end;height:150px;margin-top:16px}.dps-bar{background:#dbeafe;border:1px solid #93c5fd;border-radius:8px 8px 0 0;min-height:4px;position:relative}.dps-label{text-align:center;font-size:12px;color:#475569;margin-top:4px}.dps-table{margin-top:12px;display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:6px}.dps-cell{background:#f8f9fa;border-radius:8px;padding:8px;font-size:13px}.dps-out{margin-top:10px;padding:10px;border-radius:8px;background:#e8f4fd;border-left:4px solid #007bff}'; document.head.appendChild(s); }
  function mount(host) { if (!host || host.dataset.dpsMounted) return; host.dataset.dpsMounted = '1'; addStyle(); var faces = ['⚀','⚁','⚂','⚃','⚄','⚅'], counts = Array(13).fill(0), rolls = 0, last = [1, 1], ways = {2:1,3:2,4:3,5:4,6:5,7:6,8:5,9:4,10:3,11:2,12:1}; host.innerHTML = '<div class="dps-wrap"><h4>🎲 Mô phỏng xác suất hai xúc xắc</h4><div class="dps-dice"><button type="button" class="dps-die" data-die="0">⚀</button><button type="button" class="dps-die" data-die="1">⚀</button></div><div class="dps-actions"><button type="button" data-roll>Tung xúc xắc</button><button type="button" data-100>Tung 100 lần</button></div><div class="dps-out"></div><div class="dps-bars"></div><div class="dps-table"></div></div>'; var dice = host.querySelectorAll('.dps-die'), out = host.querySelector('.dps-out'), bars = host.querySelector('.dps-bars'), table = host.querySelector('.dps-table'); function rollOne() { last = [1 + Math.floor(Math.random() * 6), 1 + Math.floor(Math.random() * 6)]; counts[last[0] + last[1]]++; rolls++; paint(); } function paint() { dice[0].textContent = faces[last[0] - 1]; dice[1].textContent = faces[last[1] - 1]; var max = Math.max(1, Math.max.apply(null, counts)); bars.innerHTML = ''; for (var s = 2; s <= 12; s++) bars.innerHTML += '<div><div class="dps-bar" style="height:' + (counts[s] / max * 130 + 4) + 'px"></div><div class="dps-label">' + s + '</div></div>'; table.innerHTML = ''; for (s = 2; s <= 12; s++) { var exp = rolls ? (counts[s] / rolls * 100).toFixed(1) : '0.0'; table.innerHTML += '<div class="dps-cell"><strong>Tổng ' + s + '</strong><br>Thực nghiệm: ' + exp + '%<br>Lý thuyết: ' + (ways[s] / 36 * 100).toFixed(1) + '%</div>'; } out.innerHTML = 'Lần tung: <strong>' + rolls + '</strong>. Kết quả mới nhất: ' + last[0] + ' + ' + last[1] + ' = <strong>' + (last[0] + last[1]) + '</strong>.'; } host.querySelector('[data-roll]').addEventListener('click', rollOne); host.querySelector('[data-100]').addEventListener('click', function () { for (var i = 0; i < 100; i++) rollOne(); }); dice.forEach(function (d) { d.addEventListener('click', rollOne); }); paint(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="dice-probability-simulator"]').forEach(mount); });
}());
